insert TB_CS_MEETING (
	subject
	, lang
	, time_duration_ms
	, file_org_nm
	, file_new_nm
	, file_conv_nm
	, file_size_bytes
	, TC_USER_SEQ
	, error_message
	, upload_type
) value (
	#{subject}
	, #{lang}
	, #{timeDurationStr}
	, #{orgnm}
	, #{newnm}
	, #{convnm}
	, #{fileSizeBytes}
	, #{tcUserSeq}
	, #{errorMessage}
	, #{type}
)

